changeSet.sql:
            update dm.msr_prd set is_end_of_week = true where EXTRACT(ISODOW FROM eff_dttm)=7;
            update dm.msr_prd set is_end_of_month = true where msr_prd_tp_id=1 and date_trunc('day',eff_dttm)=
(date_trunc('month', eff_dttm::date) + interval '1 month' - interval '1 day')::date;
    update dm.msr_prd set is_end_of_quarter=true where msr_prd_tp_id=1  and eff_dttm::date in ('2019-03-31','2019-06-30','2019-09-30','2019-12-31',
                                                                '2020-03-31','2020-06-30','2020-09-30','2020-12-31');
update dm.msr_prd set is_end_of_half=true where msr_prd_tp_id=1  and eff_dttm::date in ('2019-06-30','2019-12-31',
                                                                '2020-06-30','2020-12-31');
update dm.msr_prd set is_end_of_year=true where msr_prd_tp_id=1  and eff_dttm::date in ('2019-12-31','2020-12-31');

rollback.sql:
update dm.msr_prd set is_end_of_week=false;
update dm.msr_prd set is_end_of_month=false;
update dm.msr_prd set is_end_of_quarter=false;
update dm.msr_prd set is_end_of_half=false;
update dm.msr_prd set is_end_of_year=false;
